    public static VanillaItem findItem(ResourceLocation identifier) {
        return ITEMS.get(identifier);
    }

    public static List<VanillaItem> findItems(Predicate<VanillaItem> filter) {
        List<VanillaItem> items = new ArrayList<>();
        for (VanillaItem item : ITEMS.values()) {
            if (filter.test(item)) {
                items.add(item);
            }
        }
        return items;
    }

    private static VanillaItem register(String identifier, MinecraftVersion[] versions) {
        VanillaItem vanillaItem = VanillaItem.of(identifier, versions);
        ITEMS.put(vanillaItem.identifier(), vanillaItem);
        return vanillaItem;
    }
